import{_ as a,W as e,X as i,Y as r}from"./framework-b9c734bc.js";const h={},l=r('<h2 id="_1-web相关概念回顾" tabindex="-1"><a class="header-anchor" href="#_1-web相关概念回顾" aria-hidden="true">#</a> 1. web相关概念回顾</h2><h3 id="_1-1-软件架构" tabindex="-1"><a class="header-anchor" href="#_1-1-软件架构" aria-hidden="true">#</a> 1.1. 软件架构</h3><ol><li>C/S：客户端/服务器端</li><li>B/S：浏览器/服务器端</li></ol><h3 id="_1-2-资源分类" tabindex="-1"><a class="header-anchor" href="#_1-2-资源分类" aria-hidden="true">#</a> 1.2. 资源分类</h3><ol><li>静态资源：所有用户访问后，得到的结果都是一样的，称为静态资源.静态资源可以直接被浏览器解析。如： html，css，JavaScript。</li><li>动态资源:每个用户访问相同资源后，得到的结果可能不一样。称为动态资源。动态资源被访问后，需要先转换为静态资源，在返回给浏览器。如：servlet/jsp，php，asp。</li></ol><h3 id="_1-3-网络通信三要素" tabindex="-1"><a class="header-anchor" href="#_1-3-网络通信三要素" aria-hidden="true">#</a> 1.3. 网络通信三要素</h3><ol><li>IP：电子设备(计算机)在网络中的唯一标识；</li><li>端口：应用程序在计算机中的唯一标识，范围为0~65536。</li><li>传输协议：规定了数据传输的规则。</li></ol><h4 id="_1-3-1-基础协议" tabindex="-1"><a class="header-anchor" href="#_1-3-1-基础协议" aria-hidden="true">#</a> 1.3.1. 基础协议</h4><ol><li>tcp：安全协议，三次握手，速度稍慢。</li><li>udp：不安全协议，速度快。</li></ol><h2 id="_2-web服务器软件" tabindex="-1"><a class="header-anchor" href="#_2-web服务器软件" aria-hidden="true">#</a> 2. web服务器软件</h2><h3 id="_2-1-服务器" tabindex="-1"><a class="header-anchor" href="#_2-1-服务器" aria-hidden="true">#</a> 2.1. 服务器</h3><p>安装了服务器软件的计算机，属于硬件资源。</p><h3 id="_2-2-服务器软件" tabindex="-1"><a class="header-anchor" href="#_2-2-服务器软件" aria-hidden="true">#</a> 2.2. 服务器软件</h3><p>接收用户的请求，处理请求，做出响应，如MySQL服务器软件。</p><h3 id="_2-3-web服务器软件" tabindex="-1"><a class="header-anchor" href="#_2-3-web服务器软件" aria-hidden="true">#</a> 2.3. web服务器软件</h3><p>也能和服务器软件一样接收用户的请求，处理请求，做出响应，并且在web服务器软件中，可以部署web项目，让用户通过浏览器来访问这些项目。</p><blockquote><p>动态资源只能在web服务器（Web容器）中运行。</p></blockquote><h3 id="_2-4-常见的java相关的web服务器软件" tabindex="-1"><a class="header-anchor" href="#_2-4-常见的java相关的web服务器软件" aria-hidden="true">#</a> 2.4. 常见的java相关的web服务器软件</h3><ol><li>webLogic：oracle公司，大型的JavaEE服务器，支持所有的JavaEE规范，收费的；</li><li>webSphere：IBM公司，大型的JavaEE服务器，支持所有的JavaEE规范，收费的；</li><li>JBOSS：JBOSS公司的，大型的JavaEE服务器，支持所有的JavaEE规范，收费的；</li><li>Tomcat：Apache基金组织，中小型的JavaEE服务器，仅仅支持少量的JavaEE规范servlet/jsp。开源的，免费的。</li></ol><blockquote><p>JavaEE规范：Java语言在企业级开发(JavaEE)中使用的技术规范的总和，一共规定了13项大的规范。</p></blockquote>',20),d=[l];function t(c,o){return e(),i("div",null,d)}const s=a(h,[["render",t],["__file","1.WEBServer-base.html.vue"]]);export{s as default};
